mapper.select:
SELECT
t.*,
t1.real_name create_user_name
FROM
castle_config_task t
LEFT OUTER JOIN castle_sys_user t1 ON t.create_user  = t1.id
WHERE
t.is_deleted = 2

    AND t.id = #{configTaskEntity.id}


    AND t.task_name like concat('%',#{configTaskEntity.taskName},'%')


    AND t.params like concat('%',#{configTaskEntity.params},'%')


    AND t.cron_expression = #{configTaskEntity.cronExpression}


    AND t.status = #{configTaskEntity.status}


    AND t.create_user = #{configTaskEntity.createUser}


    AND t.create_time = #{configTaskEntity.createTime}


    AND t.update_user = #{configTaskEntity.updateUser}


    AND t.update_time = #{configTaskEntity.updateTime}


    AND t.is_deleted = #{configTaskEntity.isDeleted}

order by create_time desc

    limit #{map.offset},#{map.rows}

SELECT
    count(1)
FROM
castle_config_task t
WHERE
    t.is_deleted = 2

    AND t.id = #{configTaskEntity.id}


    AND t.task_name like concat('%',#{configTaskEntity.taskName},'%')


    AND t.params like concat('%',#{configTaskEntity.params},'%')


    AND t.cron_expression = #{configTaskEntity.cronExpression}


    AND t.status = #{configTaskEntity.status}


    AND t.create_user = #{configTaskEntity.createUser}


    AND t.create_time = #{configTaskEntity.createTime}


    AND t.update_user = #{configTaskEntity.updateUser}


    AND t.update_time = #{configTaskEntity.updateTime}


    AND t.is_deleted = #{configTaskEntity.isDeleted}
